/// autogenintrules.py:14-18 `_eq(box1, bound1, box2, bound2)` helper:
/// `if box1 is box2: return True` — pure object identity, which is
/// `Operand`'s `==` (`Rc::ptr_eq` on every variant, two separately-minted
/// equal Consts are NOT equal). NOT `same_box`, which value-compares Const
/// operands; the constant-bound equality fallback below already covers two
/// equal Const operands, so `_eq` matches `is` semantics. Used by the
/// `optimize_INT_*` bodies that resolve operands to their `_forwarded`
/// terminal via `resolve_box`.
fn autogen_eq_b(box1: &Operand, bound1: &IntBound, box2: &Operand, bound2: &IntBound) -> bool {
    if box1 == box2 {
        return true;
    }
    if bound1.is_constant()
        && bound2.is_constant()
        && bound1.get_constant_int() == bound2.get_constant_int()
    {
        return true;
    }
    false
}

/// autogenintrules.py:54-55 rewrite helper:
/// `newop = self.replace_op_with(op, opcode, args=[...]);
///  self.optimizer.send_extra_operation(newop); return`.
/// Builds a fresh `Op` that reuses the original `op.pos` (preserving
/// Box identity) and returns `OptimizationResult::Restart` so the
/// dispatcher re-runs the new op from `first_optimization`, letting
/// chained OptIntBounds rules (add_zero, int_is_zero, further reassoc)
/// fire on the rewritten op. RPython's `send_extra_operation(opt=None)`
/// (optimizer.py:567-589) is what the dispatcher's `Restart` arm models.
fn replace_with(original: &Op, opcode: OpCode, args: &[Operand]) -> OptimizationResult {
    let new_op = Op::new(opcode, args);
    new_op.pos.set(original.pos.get());
    OptimizationResult::Restart(new_op)
}

/// autogenintrules.py helper `as_operation(box, opnum)`: the producing
/// op of an operand already resolved to its terminal box
/// (`resolve_box`), returned iff its opcode matches, else None. The
/// `op in self._emittedoperations` gate (optimizer.py:369-377) lives in
/// `ctx.get_producing_op`.
fn as_operation_b(b: &Operand, opcode: OpCode, ctx: &mut OptContext) -> Option<Op> {
    let op = ctx.get_producing_op(b)?;
    if op.opcode == opcode { Some(op) } else { None }
}
